def svg_for_icon(icon_key: str | None, name: str = "", url: str = "") -> str:
    n = (name or "").lower()
    u = (url or "").lower()
    k = (icon_key or "").strip().lower()

    if "facebook" in n or "facebook.com" in u: return _ICONS["facebook"]
    if "twitter" in n or "x.com" in u or "twitter.com" in u: return _ICONS["twitter"]
    if "youtube" in n or "youtube.com" in u or "youtu.be" in u: return _ICONS["youtube"]
    if "discord" in n or "discord" in u: return _ICONS["discord"]
    if "tiktok" in n or "tiktok.com" in u: return _ICONS["tiktok"]
    if "pinterest" in n or "pinterest.com" in u: return _ICONS["pinterest"]

    if k not in _ICONS:
        k = "link"
    return _ICONS[k]
